  ('Daniel Grindrod', 'Co-Founder', 'Co-Founder & Director | Building APAC''s leading GTM Community ️ · Hello, I''m Dan! Originally from Devon, UK, I proudly call Sydney (Bondi) home. My passion for Technology and Connecting great people led me to Co-Found Launchpad Academy, 4Twenty Consulting & Tech Talks Australia. In my downtime, I''m either planning my next trip (️️️), enjoying good foods, or doing anything outdoors and sports-related (️)Over the last decade, I''ve partnered with numerous leaders of Global and Local Technology Businesses to advise and build their GTM teams across ANZ and APA', 'Greater Sydney Area', 'Senior operator with extensive ANZ market experience.', ARRAY['Scaled Founder'], 'https://linkedin.com/in/dangrindrod', NULL, NULL, 'LaunchPad', FALSE, '[{"name": "LaunchPad"}, {"name": "4Twenty Consulting"}]'::jsonb, NULL, ARRAY['australia'], NULL, 'daniel-grindrod', 'Scaled Founder', ARRAY['international_entrant'], TRUE, FALSE),
  ('Liz van Zyl', 'Head of Partnerships', 'Board member. Advisor. Head of Partnerships @ Tractor Ventures. Community builder. Founding team. Partner @ Aussie Founders Club. Nominated as Female Startup Leader of the Year ‘24 (Aus) · I operate at the junction of founders, funding, and the networks that surround them: connecting capital, grassroots communities, industry partners, and policymakers to ensure high‑potential startups have the resources and relationships they need to grow.As Head of Partnerships at Tractor Ventures, I work to expand access to non‑dilutive funding across Australia and New Zealand. Tractor has provided more than A$100 million in revenue‑aligned capital to 250+ companies and is targeting A$1 billion', 'Prahran, Victoria, Australia', 'Senior operator with extensive ANZ market experience.', ARRAY['Active Advisor', 'Sales / GTM', 'Recognised Industry Leader'], 'https://linkedin.com/in/liz-van-zyl', NULL, NULL, 'Tractor Ventures', FALSE, '[{"name": "Tractor Ventures"}, {"name": "Aussie Founders Club"}]'::jsonb, 'uk', ARRAY['uk', 'australia'], NULL, 'liz-van-zyl', 'Active Advisor', ARRAY['international_entrant'], TRUE, FALSE),
  ('Bonnie Shek', 'Director, Australia & New Zealand', 'Director, AU & NZ, Hong Kong Trade Development Council · Bonnie is a seasoned professional with marketing, business development and management experience in Asia/Pacific. Before joining the HKTDC, she spent over ten years in the telecommunications industry, being responsible for developing marketing strategy and leading the Asia/Pacific consumer team.Having grown up in Hong Kong, then living in Australia and travelling back & forth to New Zealand for over 30 years, Bonnie understands the business dynamics among the three economies. With an extensive n', 'Greater Sydney Area', '30+ years operating experience in ANZ and international markets.', ARRAY['Trade & Government'], 'https://linkedin.com/in/bonnie-shek-a728a934', NULL, NULL, 'Hong Kong Trade Development Council', FALSE, '[{"name": "Hong Kong Trade Development Council"}, {"name": "AT&T"}]'::jsonb, NULL, ARRAY['australia'], NULL, 'bonnie-shek', 'Trade & Government', ARRAY['international_entrant'], TRUE, FALSE),
